const commits = $input.all();

// Time window (UTC – GitHub safe)
const now = new Date();
const todayStart = new Date(now);
todayStart.setHours(0, 0, 0, 0);

const yesterdayStart = new Date(todayStart);
yesterdayStart.setDate(todayStart.getDate() - 1);

const formattedDate = yesterdayStart.toISOString().split('T')[0];

// Merge branches to ignore
const IGNORE_BRANCHES = ['stg', 'qa', 'dev'];

const seen = new Set();
const lines = [];

for (const item of commits) {
  const rawMsg = item.json?.commit?.message;
  const author = item.json?.commit?.author?.name;
  const dateStr = item.json?.commit?.author?.date;

  if (!rawMsg || !dateStr) continue;

  const commitDate = new Date(dateStr);
  if (commitDate < yesterdayStart || commitDate >= todayStart) continue;

  // ✅ IMPORTANT: take only the first line
  const msg = rawMsg.split('\n')[0];
  const lowerMsg = msg.toLowerCase();

  // ❌ Skip unwanted merge PRs
  if (lowerMsg.startsWith('merge pull request')) {
    const match = lowerMsg.match(/from .*\/([^ ]+)/);
    if (match) {
      const branch = match[1].toLowerCase();
      if (IGNORE_BRANCHES.includes(branch)) continue;
    }
  }

  if (seen.has(msg)) continue;
  seen.add(msg);

  lines.push(`- ${author}: ${msg}`);
}

return [
  {
    json: {
      date: formattedDate,
      text:
        lines.length > 0
          ? lines.join('\n')
          : 'No meaningful updates were made yesterday.',
    },
  },
];
